#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
Claude Ulak 1.9.0 bootstrap installer.

Usage:
  python claude_ulak_1_9_0_bootstrap.py
  python claude_ulak_1_9_0_bootstrap.py --out ./my-dir
  python claude_ulak_1_9_0_bootstrap.py --out ./my-dir --force
"""
from __future__ import annotations
import argparse, base64, io, shutil, zipfile
from pathlib import Path

PAYLOAD = ''
DEFAULT_OUT = 'claude-ulak'


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument('--out', default=DEFAULT_OUT)
    parser.add_argument('--force', action='store_true')
    args = parser.parse_args()

    out = Path(args.out).resolve()
    if out.exists() and any(out.iterdir()) and not args.force:
        raise SystemExit(f'Output directory {out} already exists and is not empty. Use --force to overwrite.')

    if out.exists() and args.force:
        shutil.rmtree(out)
    out.mkdir(parents=True, exist_ok=True)

    raw = base64.b64decode(PAYLOAD.encode('ascii'))
    with zipfile.ZipFile(io.BytesIO(raw)) as z:
        z.extractall(out.parent)

    extracted = out.parent / 'claude-ulak'
    if extracted != out:
        if out.exists():
            shutil.rmtree(out)
        extracted.rename(out)

    print('Claude Ulak 1.9.0 installed to', out)
    print('Next steps:')
    print('  1) cd', out)
    print('  2) Open the repo in Claude Code, Codex/Copilot, or Gemini CLI')
    print('  3) Read README.md and use the platform adapter docs')
    return 0


if __name__ == '__main__':
    raise SystemExit(main())
